// api/crossfade.js — unisce le clip con DISSOLVENZA (xfade) tra una e l'altra,
// applica UNA traccia musicale CC0 con dissolvenza e IMPRIME il marchio BAM Group,
// poi carica il risultato (1080p) nel bucket privato dossier-videos. Tutto ffmpeg lato server.
// Regola BAM: nessun video esce senza watermark.
import { spawn } from "child_process";
import { writeFile, readFile, mkdtemp, rm } from "fs/promises";
import os from "os";
import path from "path";
import ffmpegPath from "ffmpeg-static";

export const config = { maxDuration: 300 };

const SUPABASE_URL = "https://ftblcuklncliherrbmgz.supabase.co";
const SUPABASE_ANON = "sb_publishable_0dkncGh3Vt9Z656g8MU40g_KWCYGeOk"; // chiave pubblica
const MUSIC_POOL = [
  "https://raw.githubusercontent.com/SoundSafari/CC0-1.0-Music/main/freepd.com/Martini%20Sunset.mp3",
  "https://raw.githubusercontent.com/SoundSafari/CC0-1.0-Music/main/freepd.com/Relaxing%20Ballad.mp3",
  "https://raw.githubusercontent.com/SoundSafari/CC0-1.0-Music/main/freepd.com/Nomadic%20Sunset.mp3"
];
const MUSIC_URL = "https://raw.githubusercontent.com/SoundSafari/CC0-1.0-Music/main/freepd.com/Nomadic%20Sunset.mp3"; // traccia master fissa (Nomadic Sunset)
const WATERMARK_B64 = ""; // marchio BAM Group trasparente (PNG)
const T = 1.0;        // durata della dissolvenza morbida (secondi) — veloce ma sfumata
const W = 2560, H = 1440;

function run(args) {
  return new Promise(function (resolve) {
    const p = spawn(ffmpegPath, args);
    let err = "";
    p.stderr.on("data", function (d) { err += d.toString(); });
    p.on("close", function (code) { resolve({ code: code, err: err }); });
    p.on("error", function (e) { resolve({ code: -1, err: String(e) }); });
  });
}

function parseDurFps(stderr) {
  let dur = 0, fps = 24;
  const dm = stderr.match(/Duration:\s*(\d+):(\d+):(\d+\.\d+)/);
  if (dm) dur = (+dm[1]) * 3600 + (+dm[2]) * 60 + parseFloat(dm[3]);
  const fm = stderr.match(/,\s*([\d.]+)\s*fps/);
  if (fm) fps = parseFloat(fm[1]);
  return { dur: dur, fps: fps };
}

async function download(url, dest) {
  const r = await fetch(url);
  if (!r.ok) throw new Error("download " + r.status);
  const buf = Buffer.from(await r.arrayBuffer());
  await writeFile(dest, buf);
}

export default async function handler(req, res) {
  if (req.method !== "POST") return res.status(405).json({ error: "Method not allowed" });

  // --- lettura body robusta ---
  let body = req.body;
  if (typeof body === "string") { try { body = JSON.parse(body); } catch (_) { body = {}; } }
  if (!body || typeof body !== "object") body = {};

  // urls di norma e' un array; in casi rari puo' arrivare come stringa JSON
  let urlsRaw = body.urls;
  if (typeof urlsRaw === "string") { try { urlsRaw = JSON.parse(urlsRaw); } catch (_) { urlsRaw = []; } }
  if (!Array.isArray(urlsRaw)) urlsRaw = [];

  const jwt = body.jwt;
  const outPath = body.path;

  console.log("[crossfade] in: urls=" + urlsRaw.length + " jwt=" + (!!jwt) + " path=" + (!!outPath));

  if (!urlsRaw.length || !jwt || !outPath) {
    console.log("[crossfade] 400 missing: urls=" + urlsRaw.length + " jwt=" + (!!jwt) + " path=" + (!!outPath));
    return res.status(400).json({ error: "Missing urls/jwt/path", urls: urlsRaw.length, jwt: !!jwt, path: !!outPath });
  }
  if (/\.\./.test(String(outPath))) return res.status(400).json({ error: "Bad path" });

  // tengo solo URL https validi (scarto vuoti/duplicati che farebbero fallire l'unione)
  const seen = {};
  const urls = [];
  for (let i = 0; i < urlsRaw.length; i++) {
    let u = urlsRaw[i];
    if (typeof u !== "string") continue;
    u = u.trim();
    if (/^https:\/\//.test(u) && !seen[u]) { seen[u] = 1; urls.push(u); }
  }
  if (urls.length < 2) {
    console.log("[crossfade] 400 <2 valide: ricevute=" + urlsRaw.length + " valide=" + urls.length + " campione=" + JSON.stringify(urlsRaw).slice(0, 400));
    return res.status(400).json({ error: "Servono almeno 2 clip valide", ricevute: urlsRaw.length, valide: urls.length });
  }

  let dir;
  try {
    dir = await mkdtemp(path.join(os.tmpdir(), "xf-"));

    // 1) scarico le clip e la musica IN PARALLELO (piu' veloce -> piu' margine sotto i 60s).
    //    Tollerante: se una clip non si scarica, uso le altre. L'ordine viene preservato.
    const downloadErrors = [];
    const musicFile = path.join(dir, "music.mp3");
    const clipResults = await Promise.all([
      Promise.all(urls.map(async function (u, i) {
        const f = path.join(dir, "c" + i + ".mp4");
        try { await download(u, f); return { i: i, f: f }; }
        catch (e) { downloadErrors.push(String(e && e.message ? e.message : e)); return null; }
      })),
      download(MUSIC_URL, musicFile)
    ]).then(function (r) { return r[0]; });
    const files = clipResults
      .filter(Boolean)
      .sort(function (a, b) { return a.i - b.i; })
      .map(function (r) { return r.f; });
    if (files.length < 2) {
      return res.status(502).json({ error: "Clip non scaricabili (link scaduti?)", dettagli: downloadErrors });
    }

    // 2) durata + fps di ogni clip
    const durs = [];
    let fps = 24;
    for (let i = 0; i < files.length; i++) {
      const probe = await run(["-i", files[i]]);
      const d = parseDurFps(probe.err);
      durs.push(d.dur || 8);
      if (i === 0 && d.fps) fps = d.fps;
    }

    // 3) filtro: normalizzo+upscale morbido a 1080p, catena di dissolvenze, musica, marchio BAM
    const parts = [];
    for (let k = 0; k < files.length; k++) {
      parts.push("[" + k + ":v]fps=" + fps + ",format=yuv420p,scale=" + W + ":" + H + ":force_original_aspect_ratio=decrease:flags=lanczos,pad=" + W + ":" + H + ":-1:-1,setsar=1,settb=AVTB[n" + k + "]");
    }
    let label = "n0", total = durs[0];
    for (let k = 1; k < files.length; k++) {
      const off = Math.max(0, Math.round((total - T) * 1000) / 1000);
      const out = (k === files.length - 1) ? "vout" : ("v" + k);
      parts.push("[" + label + "][n" + k + "]xfade=transition=fade:duration=" + T + ":offset=" + off + "[" + out + "]");
      label = out; total = total + durs[k] - T;
    }
    const fadeOut = Math.max(2, Math.min(3, Math.round(total * 0.15 * 1000) / 1000));
    const fadeIn = Math.min(1.2, Math.round(total * 0.08 * 1000) / 1000);
    const fadeAt = Math.max(0, Math.round((total - fadeOut) * 1000) / 1000);
    const musicIdx = files.length;
    parts.push("[" + musicIdx + ":a]volume=0.85,afade=t=in:st=0:d=" + fadeIn + ",afade=t=out:st=" + fadeAt + ":d=" + fadeOut + "[aout]");
    // nitidezza leggera. Il marchio BAM e' gia' impresso su OGNI clip da save-video:
    // qui NON lo ristampo, cosi' niente doppio timbro / fondo nero.
    parts.push("[vout]unsharp=5:5:0.5:3:3:0.2[vfinal]");
    const fc = parts.join(";");

    // 4) eseguo ffmpeg
    const args = [];
    for (let i = 0; i < files.length; i++) args.push("-i", files[i]);
    args.push("-stream_loop", "-1", "-i", musicFile, "-filter_complex", fc, "-map", "[vfinal]", "-map", "[aout]", "-t", String(total),
      "-c:v", "libx264", "-pix_fmt", "yuv420p", "-preset", "veryfast", "-crf", "19", "-maxrate", "14M", "-bufsize", "28M", "-threads", "0",
      "-c:a", "aac", path.join(dir, "out.mp4"));
    const enc = await run(args);
    if (enc.code !== 0) return res.status(500).json({ error: "ffmpeg failed", detail: enc.err.slice(-400) });

    // 5) carico il risultato (1080p) nel bucket privato come l'utente
    const outBuf = await readFile(path.join(dir, "out.mp4"));
    const up = await fetch(SUPABASE_URL + "/storage/v1/object/dossier-videos/" + encodeURI(outPath), {
      method: "POST",
      headers: { "Authorization": "Bearer " + jwt, "apikey": SUPABASE_ANON, "Content-Type": "video/mp4", "x-upsert": "true" },
      body: outBuf
    });
    if (!up.ok) { const t = await up.text(); return res.status(up.status).json({ error: "Upload failed: " + t.slice(0, 300) }); }

    return res.status(200).json({ ok: true, path: outPath, seconds: Math.round(total), clip_usate: files.length });
  } catch (e) {
    return res.status(500).json({ error: e && e.message ? e.message : String(e) });
  } finally {
    if (dir) { try { await rm(dir, { recursive: true, force: true }); } catch (_) {} }
  }
}
